<?php $statusLabels=['new'=>'Comandă nouă','confirmed'=>'Confirmată','processing'=>'În pregătire','ready_for_shipping'=>'Pregătită pentru curier','shipped'=>'Expediată','delivered'=>'Livrată','cancelled'=>'Anulată','return_requested'=>'Retur solicitat','returned'=>'Returnată','partially_refunded'=>'Rambursată parțial','refunded'=>'Rambursată']; ?>
<section class="page-hero shell section-space-small"><p class="eyebrow">DIN ATELIER SPRE TINE</p><h1>Urmărește comanda</h1><p><?= $order?'Comanda a fost identificată automat din linkul securizat primit pe email.':'Introdu numărul comenzii și adresa de email folosită la checkout.' ?></p></section>
<section class="tracking-card shell section-space-small"><form method="post" action="<?= e(url('/urmarire-comanda')) ?>"><?= csrf_field() ?><label>Număr comandă<input name="order_number" required placeholder="MB20260710-..." value="<?= e($number) ?>"></label><label>Email<input type="email" name="email" required value="<?= e($email) ?>"></label><button class="button" type="submit">Urmărește</button></form><?php if($error): ?><div class="form-error" role="alert"><?= e($error) ?></div><?php endif; ?><?php if($order): ?><div class="tracking-result"><div class="tracking-head"><div><small>Comanda</small><strong><?= e($order['order_number']) ?></strong></div><span><?= e($statusLabels[$order['order_status']]??$order['order_status']) ?></span></div><ol class="timeline"><?php foreach($history as $event): ?><li><strong><?= e($event['public_label']) ?></strong><p><?= e($event['public_message']) ?></p><time><?= date('d.m.Y H:i',strtotime($event['created_at'])) ?></time></li><?php endforeach; ?></ol><?php if($shipment&&$shipment['awb']): ?><a class="button button-outline" href="<?= e($shipment['tracking_url']) ?>" rel="noopener">AWB <?= e($shipment['awb']) ?></a><?php endif; ?></div><?php endif; ?></section>